module RefModule (
    input clk,
    input rst,
    input en,
    output [7:0] q
);

    reg [7:0] unused_q_reg;

    always @(posedge clk) begin
        if (rst)
            unused_q_reg <= 8'b00000000;
        else if (en)
            unused_q_reg <= unused_q_reg + 1;
    end

    assign q = unused_q_reg;

endmodule
